147→func (h *Handler) handleAnalyze(resp Response, req Request) Response {
148→	if req.File == "" {
149→		resp.Status = "error"
150→		resp.Code = ErrInvalidRequest
151→		resp.Message = "analyze command requires a file path"
152→		return resp
153→	}
154→
155→	if _, err := os.Stat(req.File); err != nil {
156→		resp.Status = "error"
157→		resp.Code = ErrFileNotFound
158→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
159→		return resp
160→	}
161→
162→	h.lastAnalyzedFile = req.File
163→
164→	var functionName string
165→	if req.Function != nil {
166→		functionName = *req.Function
167→	}
168→
169→	functions, err := AnalyzeFile(req.File, functionName)
170→	if err != nil {
171→		if functionName != "" && isNotFound(err) {
172→			resp.Status = "error"
173→			resp.Code = "function_not_found"
174→			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
175→			return resp
176→		}
177→		resp.Status = "error"
178→		resp.Code = ErrParseError
179→		resp.Message = err.Error()
180→		return resp
181→	}
182→
183→	resp.Status = "analyze"
184→	if functions == nil {
185→		functions = []FunctionAnalysis{}
186→	}
187→	resp.Functions = functions
188→	return resp
189→}
190→
191→func isNotFound(err error) bool {
192→	return err != nil && strings.HasPrefix(err.Error(), "function not found")
193→}
