397→func (h *Handler) handleSetup(resp Response, req Request) Response {
398→	resp.Status = "error"
399→	resp.Code = ErrInternalError
400→	resp.Message = "setup command not yet implemented"
401→	return resp
402→}
403→
404→func (h *Handler) handleTeardown(resp Response, req Request) Response {
405→	resp.Status = "error"
406→	resp.Code = ErrInternalError
407→	resp.Message = "teardown command not yet implemented"
408→	return resp
409→}
410→
411→func (h *Handler) handleGenerate(resp Response, req Request) Response {
412→	if req.File == "" {
413→		resp.Status = "error"
414→		resp.Code = ErrInvalidRequest
415→		resp.Message = "generate command requires a file path"
416→		return resp
417→	}
418→	if req.Name == "" {
419→		resp.Status = "error"
420→		resp.Code = ErrInvalidRequest
421→		resp.Message = "generate command requires a name"
422→		return resp
423→	}
424→
425→	var recipe json.RawMessage
426→	if req.Recipe != nil {
427→		recipe = *req.Recipe
428→	}
429→
430→	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
431→	if err != nil {
432→		resp.Status = "error"
433→		resp.Code = ErrInternalError
434→		resp.Message = fmt.Sprintf("generate failed: %v", err)
435→		return resp
436→	}
437→
438→	resp.Status = "generate"
439→	valCopy := json.RawMessage(value)
440→	resp.Value = &valCopy
441→	resp.GeneratorID = generatorID
442→	if outRecipe != nil {
443→		recipeCopy := json.RawMessage(outRecipe)
444→		resp.Recipe = &recipeCopy
445→	}
446→	return resp
447→}
448→
449→// Registry returns the generator registry, allowing custom builds to register
450→// native generators before calling Run().
451→func (h *Handler) Registry() *generators.Registry {
452→	return h.registry
453→}
454→
455→func (h *Handler) handleShutdown(resp Response) Response {
456→	h.registry.Close()
457→	resp.Status = "shutdown_ack"
458→	return resp
459→}
460→
461→func (h *Handler) send(resp Response) error {
462→	data, err := json.Marshal(resp)
463→	if err != nil {
464→		return fmt.Errorf("marshaling response: %w", err)
465→	}
466→	line := string(data) + "\n"
467→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
468→	_, err = io.WriteString(h.writer, line)
469→	return err
470→}
