683→func TestNewCommandsInConversationSequence(t *testing.T) {
684→	responses := conversation(t,
685→		reqJSON(1, "handshake", `"capabilities":["analyze"]`),
686→		reqJSON(2, "setup", `"file":"./setup.ts","function":"fn1","mode":"per_function"`),
687→		reqJSON(3, "teardown", `"function":"fn1"`),
688→		reqJSON(4, "generate", `"file":"./gen.ts","name":"User","kind":"type_name"`),
689→		reqJSON(5, "shutdown"),
690→	)
691→	if len(responses) != 5 {
692→		t.Fatalf("got %d responses, want 5", len(responses))
693→	}
694→	if responses[0].Status != "handshake" {
695→		t.Errorf("response[0].status = %q, want handshake", responses[0].Status)
696→	}
697→	if responses[1].Status != "error" || responses[1].Code != "internal_error" {
698→		t.Errorf("response[1] = status:%q code:%q, want error/internal_error", responses[1].Status, responses[1].Code)
699→	}
700→	if responses[2].Status != "error" || responses[2].Code != "internal_error" {
