  1→package protocol
  2→
  3→import (
  4→	"bufio"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"log/slog"
 10→	"os"
 11→	"strings"
 12→
 13→	"github.com/shatter-dev/shatter/shatter-go/generators"
 14→	"github.com/shatter-dev/shatter/shatter-go/instrument"
 15→)
 16→
 17→const frontendVersion = "0.1.0"
 18→const frontendLanguage = "go"
 19→
 20→// Handler processes protocol requests and writes responses.
 21→type Handler struct {
 22→	reader           *bufio.Scanner
 23→	writer           io.Writer
 24→	log              *slog.Logger
 25→	lastAnalyzedFile string // remembered from the most recent analyze command
 26→	registry         *generators.Registry
 27→}
 28→
 29→// NewHandler creates a handler reading from r, writing responses to w,
 30→// and logging to logw at the level set by SHATTER_LOG_LEVEL.
 31→func NewHandler(r io.Reader, w io.Writer, logw io.Writer) *Handler {
 32→	scanner := bufio.NewScanner(r)
 33→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024) // 10MB max line
 34→	return &Handler{
 35→		reader:   scanner,
 36→		writer:   w,
 37→		log:      slog.New(newPrefixHandler(logw, slogLevelFromEnv())),
 38→		registry: generators.NewRegistry(),
 39→	}
 40→}
 41→
 42→// NewHandlerWithLogLevel creates a handler with an explicit log level (for testing).
 43→func NewHandlerWithLogLevel(r io.Reader, w io.Writer, logw io.Writer, level string) *Handler {
 44→	scanner := bufio.NewScanner(r)
 45→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
 46→	return &Handler{
 47→		reader:   scanner,
 48→		writer:   w,
 49→		log:      slog.New(newPrefixHandler(logw, slogLevelFromString(level))),
 50→		registry: generators.NewRegistry(),
 51→	}
 52→}
 53→
 54→// Run processes requests until shutdown or EOF. Returns nil on clean shutdown.
 55→func (h *Handler) Run() error {
 56→	h.log.Debug("Starting Go frontend", "protocol", ProtocolVersion)
 57→
 58→	for h.reader.Scan() {
 59→		line := h.reader.Text()
 60→		if line == "" {
 61→			continue
 62→		}
 63→
 64→		h.log.Log(context.Background(), LevelTrace, "Received", "raw", line)
 65→
 66→		var req Request
 67→		if err := json.Unmarshal([]byte(line), &req); err != nil {
 68→			h.log.Log(context.Background(), LevelTrace, "Failed to parse request", "err", err)
 69→			continue
 70→		}
 71→
 72→		resp, shutdown := h.dispatch(req)
 73→		if err := h.send(resp); err != nil {
 74→			return fmt.Errorf("writing response: %w", err)
 75→		}
 76→
 77→		if shutdown {
 78→			h.log.Debug("Shutting down")
 79→			return nil
 80→		}
 81→	}
 82→
 83→	if err := h.reader.Err(); err != nil {
 84→		return fmt.Errorf("reading stdin: %w", err)
 85→	}
 86→
 87→	h.log.Debug("Stdin closed, exiting")
 88→	return nil
 89→}
 90→
 91→func (h *Handler) dispatch(req Request) (Response, bool) {
 92→	base := Response{
 93→		ProtocolVersion: ProtocolVersion,
 94→		ID:              req.ID,
 95→	}
 96→
 97→	if req.ProtocolVersion != ProtocolVersion {
 98→		base.Status = "error"
 99→		base.Code = ErrVersionMismatch
100→		base.Message = fmt.Sprintf(
101→			"unsupported protocol version %q, expected %q",
102→			req.ProtocolVersion, ProtocolVersion,
103→		)
104→		return base, false
105→	}
106→
107→	switch req.Command {
108→	case "handshake":
109→		return h.handleHandshake(base, req), false
110→	case "analyze":
111→		return h.handleAnalyze(base, req), false
112→	case "instrument":
113→		return h.handleInstrument(base, req), false
114→	case "execute":
115→		return h.handleExecute(base, req), false
116→	case "setup":
117→		return h.handleSetup(base, req), false
118→	case "teardown":
119→		return h.handleTeardown(base, req), false
120→	case "generate":
121→		return h.handleGenerate(base, req), false
122→	case "shutdown":
123→		return h.handleShutdown(base), true
124→	default:
125→		base.Status = "error"
126→		base.Code = ErrInvalidRequest
127→		base.Message = fmt.Sprintf("unknown command: %s", req.Command)
128→		return base, false
129→	}
130→}
131→
132→func (h *Handler) handleHandshake(resp Response, req Request) Response {
133→	resp.Status = "handshake"
134→	resp.FrontendVersion = frontendVersion
135→	resp.Language = frontendLanguage
136→	caps := make([]string, len(CommandCapabilities))
137→	copy(caps, CommandCapabilities)
138→	caps = append(caps,
139→		"complex_type:date", "complex_type:duration", "complex_type:url",
140→		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
141→		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
142→	)
143→	resp.Capabilities = caps
144→	return resp
145→}
146→
147→func (h *Handler) handleAnalyze(resp Response, req Request) Response {
148→	if req.File == "" {
149→		resp.Status = "error"
150→		resp.Code = ErrInvalidRequest
151→		resp.Message = "analyze command requires a file path"
152→		return resp
153→	}
154→
155→	if _, err := os.Stat(req.File); err != nil {
156→		resp.Status = "error"
157→		resp.Code = ErrFileNotFound
158→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
159→		return resp
160→	}
161→
162→	h.lastAnalyzedFile = req.File
163→
164→	var functionName string
165→	if req.Function != nil {
166→		functionName = *req.Function
167→	}
168→
169→	functions, err := AnalyzeFile(req.File, functionName)
170→	if err != nil {
171→		if functionName != "" && isNotFound(err) {
172→			resp.Status = "error"
173→			resp.Code = "function_not_found"
174→			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
175→			return resp
176→		}
177→		resp.Status = "error"
178→		resp.Code = ErrParseError
179→		resp.Message = err.Error()
180→		return resp
181→	}
182→
183→	resp.Status = "analyze"
184→	if functions == nil {
185→		functions = []FunctionAnalysis{}
186→	}
187→	resp.Functions = functions
188→	return resp
189→}
190→
191→func isNotFound(err error) bool {
192→	return err != nil && strings.HasPrefix(err.Error(), "function not found")
193→}
194→
195→func (h *Handler) handleInstrument(resp Response, req Request) Response {
196→	if req.File == "" {
197→		resp.Status = "error"
198→		resp.Code = ErrInvalidRequest
199→		resp.Message = "instrument command requires a file path"
200→		return resp
201→	}
202→
203→	if _, err := os.Stat(req.File); err != nil {
204→		resp.Status = "error"
205→		resp.Code = ErrFileNotFound
206→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
207→		return resp
208→	}
209→
210→	h.lastAnalyzedFile = req.File
211→
212→	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
213→	if err != nil {
214→		resp.Status = "error"
215→		resp.Code = ErrInternalError
216→		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
217→		return resp
218→	}
219→
220→	instrumented := true
221→	resp.Status = "instrument"
222→	resp.Instrumented = &instrumented
223→	resp.OutputFile = &outputDir
224→	return resp
225→}
226→
227→func (h *Handler) handleExecute(resp Response, req Request) Response {
228→	file := req.File
229→	if file == "" {
230→		file = h.lastAnalyzedFile
231→	}
232→	if file == "" {
233→		resp.Status = "error"
234→		resp.Code = ErrInvalidRequest
235→		resp.Message = "execute command requires a file path (or a prior analyze)"
236→		return resp
237→	}
238→
239→	if req.Function == nil || *req.Function == "" {
240→		resp.Status = "error"
241→		resp.Code = ErrInvalidRequest
242→		resp.Message = "execute command requires a function name"
243→		return resp
244→	}
245→
246→	if _, err := os.Stat(file); err != nil {
247→		resp.Status = "error"
248→		resp.Code = ErrFileNotFound
249→		resp.Message = fmt.Sprintf("file not found: %s", file)
250→		return resp
251→	}
252→
253→	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
254→	var execMocks []instrument.MockConfig
255→	for _, m := range req.Mocks {
256→		execMocks = append(execMocks, instrument.MockConfig{
257→			Symbol:           m.Symbol,
258→			ReturnValues:     m.ReturnValues,
259→			ShouldTrackCalls: m.ShouldTrackCalls,
260→			DefaultBehavior:  m.DefaultBehavior,
261→		})
262→	}
263→	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
264→	if err != nil {
265→		resp.Status = "error"
266→		if strings.Contains(err.Error(), "function not found") {
267→			resp.Code = "function_not_found"
268→		} else if strings.Contains(err.Error(), "build failed") {
269→			resp.Code = "instrumentation_failed"
270→		} else if strings.Contains(err.Error(), "timed out") {
271→			resp.Code = ErrExecutionTimeout
272→		} else {
273→			resp.Code = ErrInternalError
274→		}
275→		resp.Message = err.Error()
276→		return resp
277→	}
278→
279→	resp.Status = "execute"
280→	resp.ReturnValue = result.ReturnValue
281→	resp.ThrownError = convertErrorInfo(result.ThrownError)
282→	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
283→	resp.BranchPath = convertBranchPath(result.BranchPath)
284→	resp.PathConstraints = extractPathConstraints(result.BranchPath)
285→	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
286→	resp.SideEffects = convertSideEffects(result.SideEffects)
287→	resp.ScopeEvents = result.ScopeEvents
288→	resp.Performance = &PerfMetrics{
289→		WallTimeMs:         result.Performance.WallTimeMs,
290→		CPUTimeUs:          result.Performance.CPUTimeUs,
291→		HeapUsedBytes:      result.Performance.HeapUsedBytes,
292→		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
293→	}
294→
295→	return resp
296→}
297→
298→func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
299→	if e == nil {
300→		return nil
301→	}
302→	var stack *string
303→	if e.Stack != "" {
304→		stack = &e.Stack
305→	}
306→	return &ErrorInfo{
307→		ErrorType: e.ErrorType,
308→		Message:   e.Message,
309→		Stack:     stack,
310→	}
311→}
312→
313→func toIntSlice(ints []int) []int {
314→	if ints == nil {
315→		return []int{}
316→	}
317→	return ints
318→}
319→
320→func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
321→	result := make([]BranchDecision, len(branches))
322→	for i, b := range branches {
323→		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
324→		if b.ConstraintJSON != "" {
325→			var sc SymConstraint
326→			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
327→				constraint = &sc
328→			}
329→		}
330→		result[i] = BranchDecision{
331→			BranchID:   b.BranchID,
332→			Line:       b.Line,
333→			Taken:      b.Taken,
334→			Constraint: constraint,
335→		}
336→	}
337→	return result
338→}
339→
340→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
341→	var constraints []SymConstraint
342→	for _, b := range branches {
343→		if b.ConstraintJSON == "" {
344→			continue
345→		}
346→		var sc SymConstraint
347→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
348→			constraints = append(constraints, sc)
349→		}
350→	}
351→	if constraints == nil {
