152→	// Regression test for str-xkb: doc-only files (no function definitions)
153→	// must still emit "functions":[] in JSON, not omit the field entirely.
154→	// The Rust core requires the field to be present for deserialization.
155→	tmp := filepath.Join(t.TempDir(), "doc.go")
156→	if err := os.WriteFile(tmp, []byte("// Package foo provides utilities.\npackage foo\n"), 0644); err != nil {
157→		t.Fatal(err)
158→	}
159→
160→	// Send the analyze request and capture raw JSON output
161→	input := strings.NewReader(reqJSON(3, "analyze", fmt.Sprintf(`"file":"%s"`, tmp)) + "\n")
162→	var output bytes.Buffer
163→	handler := NewHandler(input, &output, io.Discard)
164→	if err := handler.Run(); err != nil {
165→		t.Fatalf("handler.Run: %v", err)
166→	}
167→	rawJSON := strings.TrimSpace(output.String())
168→
169→	// The raw JSON must contain "functions":[] -- not omit the field
170→	if !strings.Contains(rawJSON, `"functions"`) {
171→		t.Fatalf("JSON response omits functions field entirely: %s", rawJSON)
172→	}
173→	if !strings.Contains(rawJSON, `"functions":[]`) {
174→		t.Fatalf("JSON response does not contain functions:[], got: %s", rawJSON)
175→	}
176→
177→	// Also verify it deserializes correctly
178→	var resp Response
179→	if err := json.Unmarshal([]byte(rawJSON), &resp); err != nil {
180→		t.Fatalf("unmarshal: %v", err)
181→	}
182→	if resp.Status != "analyze" {
183→		t.Errorf("status = %q, want analyze", resp.Status)
184→	}
185→	if resp.Functions == nil {
186→		t.Error("functions should be non-nil empty slice, got nil")
187→	}
188→	if len(resp.Functions) != 0 {
189→		t.Errorf("functions len = %d, want 0", len(resp.Functions))
190→	}
191→}
