103→			}
104→		}),
105→		rapid.Custom[Response](func(t *rapid.T) Response {
106→			return Response{
107→				ProtocolVersion: ProtocolVersion,
108→				ID:              rapid.IntRange(0, 1000).Draw(t, "id"),
109→				Status:          "analyze",
110→				Functions:       rapid.SliceOfN(genFunctionAnalysis(), 0, 3).Draw(t, "fns"),
111→			}
112→		}),
113→		rapid.Custom[Response](func(t *rapid.T) Response {
114→			return Response{
115→				ProtocolVersion: ProtocolVersion,
116→				ID:              rapid.IntRange(0, 1000).Draw(t, "id"),
117→				Status:          "error",
118→				Code:            rapid.SampledFrom([]string{"file_not_found", "internal_error", "parse_error"}).Draw(t, "code"),
119→				Message:         rapid.StringMatching(`.{0,30}`).Draw(t, "msg"),
120→			}
121→		}),
