220→// genNonShutdownCommand produces commands that don't require filesystem access
221→// and don't trigger shutdown. Each returns a valid response or structured error.
222→func genNonShutdownCommand() *rapid.Generator[string] {
223→	return rapid.SampledFrom([]string{
224→		"handshake",
225→		"bogus_command", // unknown → error response
226→	})
227→}
