314→// goTypeMap maps Go type names to the Shatter TypeInfo.Kind the analyzer produces.
315→var goTypeMap = map[string]string{
316→	"int":     "int",
317→	"int64":   "int",
318→	"float64": "float",
319→	"string":  "str",
320→	"bool":    "bool",
321→}
322→
323→// TestPropertyAnalyzeExtractsCorrectParams generates simple Go functions with
324→// known signatures and verifies AnalyzeFile extracts the right parameter count,
325→// names, and types.
326→func TestPropertyAnalyzeExtractsCorrectParams(t *testing.T) {
327→	rapid.Check(t, func(t *rapid.T) {
328→		goTypes := []string{"int", "int64", "float64", "string", "bool"}
329→
330→		nParams := rapid.IntRange(0, 4).Draw(t, "nParams")
331→		type paramSpec struct {
332→			name   string
333→			goType string
334→		}
335→		var params []paramSpec
336→		for i := 0; i < nParams; i++ {
337→			name := rapid.StringMatching(`[a-z][a-z0-9]{0,5}`).Draw(t, fmt.Sprintf("name%d", i))
338→			goType := rapid.SampledFrom(goTypes).Draw(t, fmt.Sprintf("type%d", i))
339→			params = append(params, paramSpec{name: name, goType: goType})
340→		}
341→
342→		// Build source
343→		var paramList []string
344→		for _, p := range params {
345→			paramList = append(paramList, fmt.Sprintf("%s %s", p.name, p.goType))
346→		}
347→		src := fmt.Sprintf("package p\n\nfunc Foo(%s) int { return 0 }\n", strings.Join(paramList, ", "))
348→
349→		// Write to temp file
350→		dir, err := os.MkdirTemp("", "shatter-go-prop-*")
351→		if err != nil {
352→			t.Fatalf("mkdirtemp: %v", err)
353→		}
354→		defer os.RemoveAll(dir)
355→		fpath := filepath.Join(dir, "test.go")
356→		if err := os.WriteFile(fpath, []byte(src), 0o644); err != nil {
357→			t.Fatalf("write temp file: %v", err)
358→		}
359→
360→		results, err := AnalyzeFile(fpath, "Foo")
361→		if err != nil {
362→			t.Fatalf("AnalyzeFile: %v", err)
363→		}
364→		if len(results) != 1 {
365→			t.Fatalf("expected 1 function, got %d", len(results))
366→		}
367→
368→		fa := results[0]
369→		if fa.Name != "Foo" {
370→			t.Fatalf("name: got %q, want %q", fa.Name, "Foo")
371→		}
372→		if len(fa.Params) != nParams {
373→			t.Fatalf("param count: got %d, want %d", len(fa.Params), nParams)
374→		}
375→		for i, p := range params {
376→			if fa.Params[i].Name != p.name {
377→				t.Fatalf("param[%d] name: got %q, want %q", i, fa.Params[i].Name, p.name)
378→			}
379→			expectedKind := goTypeMap[p.goType]
380→			if fa.Params[i].Type.Kind != expectedKind {
381→				t.Fatalf("param[%d] type: got %q, want %q (Go type %s)", i, fa.Params[i].Type.Kind, expectedKind, p.goType)
382→			}
383→		}
384→	})
385→}
