			ReturnValue: retVal,
		}
	}
	return result
}

// convertSideEffects converts executor SideEffects to protocol format.
func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
	if len(effects) == 0 {
		return []SideEffect{}
	}
	result := make([]SideEffect, len(effects))
	for i, e := range effects {
