	}

	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("generate failed: %v", err)
		return resp
	}

	resp.Status = "generate"
