}

func (h *Handler) handleShutdown(resp Response) Response {
	h.registry.Close()
	resp.Status = "shutdown_ack"
	return resp
}

func (h *Handler) send(resp Response) error {
	data, err := json.Marshal(resp)
	if err != nil {
