func TestSetupWithValidFileReturnsContext(t *testing.T) {
	// Write a setup Go file that outputs JSON context.
	dir := t.TempDir()
	setupFile := filepath.Join(dir, "setup.go")
	src := `package main

import "fmt"

func main() {
	fmt.Println("{\"db\":\"test_db\",\"ready\":true}")
