func TestSetupValidationTableDriven(t *testing.T) {
	tests := []struct {
		name     string
		request  string
		wantID   int
		wantCode string
	}{
		{
			name:     "setup missing file",
			request:  reqJSON(20, "setup", `"scope":"fn1","level":"function"`),
			wantID:   20,
			wantCode: ErrInvalidRequest,
		},
		{
			name:     "setup missing scope",
			request:  reqJSON(21, "setup", `"file":"./setup.go","level":"function"`),
			wantID:   21,
			wantCode: ErrInvalidRequest,
		},
		{
			name:     "setup missing level",
			request:  reqJSON(22, "setup", `"file":"./setup.go","scope":"fn1"`),
			wantID:   22,
			wantCode: ErrInvalidRequest,
		},
		{
			name:     "setup invalid level",
			request:  reqJSON(23, "setup", `"file":"./setup.go","scope":"fn1","level":"bogus"`),
			wantID:   23,
			wantCode: ErrInvalidRequest,
		},
		{
			name:     "setup file not found",
			request:  reqJSON(24, "setup", `"file":"./nonexistent.go","scope":"fn1","level":"function"`),
			wantID:   24,
			wantCode: ErrFileNotFound,
		},
		{
			name:     "teardown missing scope",
			request:  reqJSON(25, "teardown", `"level":"function"`),
			wantID:   25,
			wantCode: ErrInvalidRequest,
		},
		{
			name:     "teardown missing level",
			request:  reqJSON(26, "teardown", `"scope":"fn1"`),
			wantID:   26,
			wantCode: ErrInvalidRequest,
		},
		{
			name:     "teardown invalid level",
			request:  reqJSON(27, "teardown", `"scope":"fn1","level":"bogus"`),
			wantID:   27,
			wantCode: ErrInvalidRequest,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			resp := sendRecv(t, tt.request)
			if resp.Status != "error" {
				t.Errorf("status = %q, want error", resp.Status)
			}
			if resp.Code != tt.wantCode {
				t.Errorf("code = %q, want %q", resp.Code, tt.wantCode)
			}
			if resp.ID != tt.wantID {
				t.Errorf("id = %d, want %d", resp.ID, tt.wantID)
			}
			if resp.ProtocolVersion != ProtocolVersion {
				t.Errorf("protocol_version = %q, want %s", resp.ProtocolVersion, ProtocolVersion)
			}
		})
	}
}

