func TestNewCommandRequestDeserialization(t *testing.T) {
	tests := []struct {
		name     string
		json     string
		wantCmd  string
		wantFile string
		wantFunc string
	}{
		{
			name:     "setup request",
			json:     reqJSON(1, "setup", `"file":"./setup.ts","function":"fn1","mode":"per_function"`),
			wantCmd:  "setup",
			wantFile: "./setup.ts",
			wantFunc: "fn1",
		},
		{
			name:    "teardown request",
			json:    reqJSON(2, "teardown", `"function":"fn1"`),
			wantCmd: "teardown",
		},
		{
			name:     "generate request",
			json:     reqJSON(3, "generate", `"file":"./gen.ts","name":"User","kind":"type_name"`),
			wantCmd:  "generate",
			wantFile: "./gen.ts",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var req Request
			if err := json.Unmarshal([]byte(tt.json), &req); err != nil {
				t.Fatalf("unmarshal: %v", err)
			}
			if req.Command != tt.wantCmd {
				t.Errorf("command = %q, want %q", req.Command, tt.wantCmd)
			}
			if tt.wantFile != "" && req.File != tt.wantFile {
				t.Errorf("file = %q, want %q", req.File, tt.wantFile)
			}
			if tt.wantFunc != "" {
				if req.Function == nil || *req.Function != tt.wantFunc {
					got := "<nil>"
					if req.Function != nil {
						got = *req.Function
					}
					t.Errorf("function = %q, want %q", got, tt.wantFunc)
				}
			}
		})
	}
}

