 16→// ---------------------------------------------------------------------------
 17→// Generators
 18→// ---------------------------------------------------------------------------
 19→
 20→func genIdent() *rapid.Generator[string] {
 21→	return rapid.StringMatching(`[a-zA-Z_][a-zA-Z0-9_]{0,12}`)
 22→}
 23→
 24→func genTypeInfoLeaf() *rapid.Generator[TypeInfo] {
 25→	return rapid.Map(
 26→		rapid.SampledFrom([]string{"int", "float", "str", "bool", "unknown"}),
 27→		func(kind string) TypeInfo { return TypeInfo{Kind: kind} },
 28→	)
 29→}
 30→
 31→func genTypeInfo(depth int) *rapid.Generator[TypeInfo] {
 32→	if depth <= 0 {
 33→		return genTypeInfoLeaf()
 34→	}
 35→	return rapid.OneOf(
 36→		genTypeInfoLeaf(),
 37→		rapid.Map(genTypeInfo(depth-1), func(elem TypeInfo) TypeInfo {
 38→			return TypeInfo{Kind: "array", Element: &elem}
 39→		}),
 40→		rapid.Map(genTypeInfo(depth-1), func(inner TypeInfo) TypeInfo {
 41→			return TypeInfo{Kind: "nullable", Inner: &inner}
 42→		}),
 43→		rapid.Map(
 44→			rapid.SliceOfN(genTypeInfo(depth-1), 2, 3),
 45→			func(variants []TypeInfo) TypeInfo {
 46→				return TypeInfo{Kind: "union", Variants: variants}
 47→			},
 48→		),
 49→		rapid.Custom[TypeInfo](func(t *rapid.T) TypeInfo {
 50→			return TypeInfo{Kind: "opaque", Label: genIdent().Draw(t, "label")}
 51→		}),
 52→	)
 53→}
 54→
 55→func genParamInfo() *rapid.Generator[ParamInfo] {
 56→	return rapid.Custom[ParamInfo](func(t *rapid.T) ParamInfo {
 57→		return ParamInfo{
 58→			Name: genIdent().Draw(t, "name"),
 59→			Type: genTypeInfo(2).Draw(t, "type"),
 60→		}
 61→	})
 62→}
 63→
 64→func genBranchInfo() *rapid.Generator[BranchInfo] {
 65→	return rapid.Custom[BranchInfo](func(t *rapid.T) BranchInfo {
 66→		return BranchInfo{
 67→			ID:            rapid.IntRange(0, 100).Draw(t, "id"),
 68→			Line:          rapid.IntRange(1, 500).Draw(t, "line"),
 69→			ConditionText: rapid.StringMatching(`.{0,20}`).Draw(t, "cond"),
 70→			Condition:     nil,
 71→			BranchType:    rapid.SampledFrom([]string{"if", "else_if", "switch", "ternary", "logical_and", "logical_or", "while", "for"}).Draw(t, "bt"),
 72→		}
 73→	})
 74→}
 75→
 76→func genFunctionAnalysis() *rapid.Generator[FunctionAnalysis] {
 77→	return rapid.Custom[FunctionAnalysis](func(t *rapid.T) FunctionAnalysis {
 78→		startLine := rapid.IntRange(1, 500).Draw(t, "start")
 79→		endLine := rapid.IntRange(startLine, startLine+200).Draw(t, "end")
 80→		return FunctionAnalysis{
