401→func (h *Handler) handleSetup(resp Response, req Request) Response {
402→	if req.File == "" {
403→		resp.Status = "error"
404→		resp.Code = ErrInvalidRequest
405→		resp.Message = "setup command requires a file path"
406→		return resp
407→	}
408→	if req.Scope == "" {
409→		resp.Status = "error"
410→		resp.Code = ErrInvalidRequest
411→		resp.Message = "setup command requires a scope"
412→		return resp
413→	}
414→	if !req.Level.IsValid() {
415→		resp.Status = "error"
416→		resp.Code = ErrInvalidRequest
417→		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
418→		return resp
419→	}
420→
421→	if _, err := os.Stat(req.File); err != nil {
422→		resp.Status = "error"
423→		resp.Code = ErrFileNotFound
424→		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
425→		return resp
426→	}
427→
428→	var parentCtxJSON json.RawMessage
429→	if req.ParentContext != nil {
430→		data, err := json.Marshal(req.ParentContext)
431→		if err != nil {
432→			resp.Status = "error"
433→			resp.Code = ErrInternalError
434→			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
435→			return resp
436→		}
437→		parentCtxJSON = data
438→	}
439→
440→	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)
441→
442→	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
443→	if err != nil {
444→		resp.Status = "error"
445→		resp.Code = ErrInternalError
446→		resp.Message = fmt.Sprintf("setup failed: %v", err)
447→		return resp
448→	}
449→
450→	resp.Status = "setup"
451→	ctxCopy := json.RawMessage(ctx)
452→	resp.SetupContext = &ctxCopy
453→	return resp
454→}
